INSERT INTO services (title, description, icon, link) VALUES 
('Hemp & CBD SEO Services', 'Industry-specific keyword research with semantic clustering and compliance-first content strategy. We understand the nuances of hemp SEO and create content that ranks while staying fully compliant with Google guidelines and state regulations. Our approach includes entity-based optimization, topical authority building, and strategic internal linking.', 'ri-search-line', 'hemp_seo_service.php'),
('Vape SEO Services', 'Specialized SEO for vape shops and vape product brands. We build algorithm-resistant rankings with age-gate optimization, device and e-liquid product page SEO, SERP volatility monitoring, and brand authority building through compliant content strategies that drive consistent traffic both locally and nationally.', 'ri-mist-line', 'vape_seo_service.php'),
('Local SEO for Dispensaries', 'Google Business Profile optimization, 500+ local citations, and location-specific landing pages. We help dispensaries dominate local search results with geo-targeted content, review management, local link building, and NAP consistency across all platforms. Perfect for multi-location cannabis businesses.', 'ri-map-pin-line', '#local-seo'),
('Google Ads for CBD (Compliant)', 'Compliant Google Ads campaigns that actually work for CBD and hemp products. We navigate the complex advertising restrictions with white-hat strategies, alternative keyword targeting, and landing page optimization that passes Google review. Achieve profitable ROAS while staying within platform guidelines.', 'ri-advertisement-line', '#google-ads'),
('Technical SEO & CRO', 'Comprehensive technical audits, Core Web Vitals optimization, and conversion rate optimization. We fix crawl errors, improve site architecture, implement structured data, and optimize page speed. Our CRO strategies include A/B testing, heat mapping analysis, and user experience improvements that increase conversions.', 'ri-line-chart-line', '#technical-seo'),
('Link Building for Hemp Brands', 'White-hat link acquisition in restricted niches with high-authority backlinks from relevant hemp, wellness, and lifestyle publications. We build sustainable link profiles through content partnerships, digital PR, and relationship building with industry influencers and authoritative websites in the cannabis space.', 'ri-links-line', '#link-building');
