('Premium CBD Brand', 'CBD Ecommerce', 'New CBD ecommerce store struggling to rank for competitive keywords and generate organic traffic', 'Implemented comprehensive Hemp SEO strategy including technical optimization, content marketing, and strategic link building', './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(12)', '385%', 'Organic Traffic Increase', '12x', 'Keyword Rankings', '$250K', 'Monthly Revenue'),
('Multi-Location Dispensary', 'Cannabis Retail', 'Dispensary chain needed to dominate local search across 8 locations in competitive markets', 'Developed location-specific landing pages, optimized Google Business Profiles, and built local citations', './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(13)', '520%', 'Local Search Visibility', '#1', 'Rankings in 6 Cities', '180%', 'Foot Traffic Growth'),
('Hemp Wellness Brand', 'Hemp Products', 'Established hemp brand losing market share to competitors with better online visibility', 'Rebuilt content strategy with entity-based SEO, improved technical performance, and acquired high-authority backlinks', './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(14)', '290%', 'Organic Revenue', '450+', 'Page 1 Rankings', '4.2x', 'ROAS');
INSERT INTO testimonials (client_name, position, company, content, rating, image_path) VALUES 
('Sarah Mitchell', 'CEO', 'GreenLeaf CBD', '"Working with this Hemp SEO Agency transformed our business. We went from page 3 to dominating page 1 for our most important keywords. Our organic traffic increased 385% in just 6 months, and revenue has tripled. They truly understand the hemp industry and compliance requirements."', 5, './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(15)'),
('Michael Chen', 'Owner', 'Urban Dispensary', '"As a multi-location dispensary, local SEO was critical for us. This team delivered beyond expectations. We now rank #1 in all our target cities, and foot traffic has increased dramatically. Their understanding of cannabis regulations and local search is unmatched."', 5, './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(16)'),
('Jennifer Rodriguez', 'Marketing Director', 'Hemp Wellness Co', '"Finally, an SEO agency that gets the hemp industry! Their strategic approach to content and link building has positioned us as an authority in our niche. We have seen consistent month-over-month growth in rankings, traffic, and most importantly, revenue."', 5, './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(17)'),
('David Thompson', 'Founder', 'Vape Nation', '"The results speak for themselves. Our vape shop went from struggling to find customers online to being the top result for dozens of high-value keywords. The Hemp SEO Agency team is responsive, transparent, and delivers real ROI."', 5, './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(18)'),
('Amanda Foster', 'Owner', 'Pure CBD Store', '"I have worked with several SEO agencies before, but none understood the unique challenges of CBD ecommerce like this team. They optimized our entire site, created amazing content, and built quality backlinks. Our sales have increased 290% year-over-year."', 5, './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(19)'),
('Robert Martinez', 'Director', 'Cannabis Collective', '"Outstanding service and results. This Hemp SEO Agency helped us navigate the complex world of cannabis marketing with compliant strategies that actually work. We have seen tremendous growth in organic visibility and customer acquisition."', 5, './Hemp%20SEO%20Agency%20_%20CBD,%20Cannabis%20&%20Vape%20SEO%20Services%20_%20HempSuccess_files/search-image(20)');
